import jwt from "jsonwebtoken";
import {
  AccessTokenPayload,
  JwtPayload,
  RefreshTokenPayload
} from "./jwt.types";
import { JwtExpiredError, JwtInvalidError } from "./jwt.errors";

function verifyToken<T extends JwtPayload>(token: string, secret: string): T {
  try {
    return jwt.verify(token, secret) as T;
  } catch (err: any) {
    if (err.name === "TokenExpiredError") {
      throw new JwtExpiredError();
    }
    throw new JwtInvalidError();
  }
}

export function verifyAccessToken(token: string) {
  return verifyToken(
    token,
    process.env.JWT_ACCESS_SECRET as string
  ) as AccessTokenPayload;
}

export function verifyRefreshToken(token: string) {
  return verifyToken(
    token,
    process.env.JWT_REFRESH_SECRET as string
  ) as RefreshTokenPayload;
}

import jwt from "jsonwebtoken";

export function decodeToken<T = unknown>(token: string): T | null {
  return jwt.decode(token) as T | null;
}

export function extractTokenFromHeader(authHeader?: string): string | null {
  if (!authHeader) return null;

  const parts = authHeader.split(" ");
  if (parts.length !== 2 || parts[0] !== "Bearer") {
    return null;
  }

  return parts[1];
}

export enum JwtType {
  ACCESS = "access",
  REFRESH = "refresh"
}

export type JwtPayloadBase = {
  sub: string;
  iat?: number;
  exp?: number;
};

export type AccessTokenPayload = JwtPayloadBase & {
  type: JwtType.ACCESS;
  email: string;
  sid: string;
};

export type RefreshTokenPayload = JwtPayloadBase & {
  type: JwtType.REFRESH;
  sid: string;
};

export type JwtPayload = AccessTokenPayload | RefreshTokenPayload;

import jwt from "jsonwebtoken";
import { AccessTokenPayload, JwtType, RefreshTokenPayload } from "./jwt.types";

export function signAccessToken(payload: {
  sub: string;
  email: string;
  sid: string;
}): string {
  const tokenPayload: AccessTokenPayload = {
    sub: payload.sub,
    type: JwtType.ACCESS,
    email: payload.email,
    sid: payload.sid
  };

  return jwt.sign(tokenPayload, process.env.JWT_ACCESS_SECRET as string, {
    expiresIn: "15m"
  });
}

export function signRefreshToken(payload: {
  sub: string;
  sid: string;
}): string {
  const tokenPayload: RefreshTokenPayload = {
    sub: payload.sub,
    type: JwtType.REFRESH,
    sid: payload.sid
  };

  return jwt.sign(tokenPayload, process.env.JWT_REFRESH_SECRET as string, {
    expiresIn: "7d"
  });
}

export class JwtError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "JwtError";
  }
}

export class JwtExpiredError extends JwtError {
  constructor() {
    super("Token expired");
  }
}

export class JwtInvalidError extends JwtError {
  constructor() {
    super("Invalid token");
  }
}

export * from "./jwt.types";
export * from "./jwt.sign";
export * from "./jwt.verify";
export * from "./jwt.utils";
export * from "./jwt.errors";
